            toStringOutput.Add($"EFormat = {this.EFormat ?? "null"}");
            toStringOutput.Add($"EKeyedData = {this.EKeyedData ?? "null"}");
            toStringOutput.Add($"RunAvs = {(this.RunAvs == null ? "null" : this.RunAvs.ToString())}");
            toStringOutput.Add($"TrackData = {this.TrackData ?? "null"}");
            toStringOutput.Add($"Ticket = {this.Ticket ?? "null"}");

            base.ToString(toStringOutput);
        }
    }
}